// // This module performs subtraction when sel is 0 and addition when sel is 1
module calculator (input [7:0] A, input [7:0] B, input sel, output reg [7:0] result);

always @(*) begin
    if(sel == 0) begin
        result = A + B;
    end else begin
        result = A - B;
    end
end

endmodule
